const Q_ECONOMICS_2021_MODEL_II=[{"id": "objective>Economics>2021 Model II>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">All except one is not an attribute to an upward sloping demand curve</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">War</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Differences in elasticity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Depression</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unrelated goods</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Many causes are attributed to an upward sloping demand , the causes are: war, Depression, Giffen goods, Ignorance effect, luxury goods/Article of ostentation, Differences in elasticity, Rare commodity, Fear of future rise in price, Snob effect.</div>", "topic": "THE THEORY OF DEMAND : MEANING AND DETERMINANTS"}, {"id": "objective>Economics>2021 Model II>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to anwer the question that follows: <br/>  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> From the diagram above, a shift in demand curve from D1 to D2 depicts</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease in demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in demand</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The diagram above represent an increase in demand. The demand curve shift to the right when supply curve remains constant.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2021 Model II>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A type of price elasticity of demand that runs parallel to axis of x is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Unitary demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Perfectly inelastic demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Infinity demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Elastic demand</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Perfectly elastic demand is also known as infinity demand. It runs parallel to axis of x and it is absolutely horizontal.</div>", "topic": "THE THEORY OF DEMAND : ELASTICITY OF DEMAND"}, {"id": "objective>Economics>2021 Model II>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a monopoly, the demand curve is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Marginal revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Marginal Cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Average revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Average cost</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The demand curve for a monopoly is the average revenue. The average revenue/demand curve slopes downwards to the left indicating a negative slope.</div>", "topic": "MARKET STRUCTURE : IMPERFECT MARKET ( MONOPOLY)"}, {"id": "objective>Economics>2021 Model II>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of excess capacity is associated with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">perfect market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monopoly</div>", "<div style=\"font-family:Cambria;font-size:17px;\">imperfect market</div>", "<div style=\"font-family:Cambria;font-size:17px;\">monopoistic competition</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The theory of excess capacity (unutilized capacity) is associated with monopolistic competition in the long-run. It is the difference between ideal (optimum) output and the actually attained in the long-run.</div>", "topic": "MARKET STRUCTURE : MONOPOLISTIC COMPETITION"}, {"id": "objective>Economics>2021 Model II>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a perfect market, the products are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">perfect substitutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">close substitutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">poor substitutes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unrelated</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a perfect market, also known as a perfectly competitive market, all products are perfect substitutes for each other. This means that the products are identical in terms of quality, size, content, etc. Therefore, consumers have no preference for any particular product and can easily substitute one product for another.</div>", "topic": "MARKET STRUCTURE : PERFECT MARKET"}, {"id": "objective>Economics>2021 Model II>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> From the diagram above, a shift in supply curve from S0 to S1 depicts </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">decrease in demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease in supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in supply</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the diagram above, the supply curve shift to the left indicating a decrease in supply at old price i.e less will be supplied.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : EFFECT OF CHANGE IN SUPPLY & DEMAND ON EQUILIBRIUM PRICE & QUANTITY"}, {"id": "objective>Economics>2021 Model II>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When a given change in price leads to a less than proportionate change in the amount supplied, supply is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">elastic supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unitary supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">perfectly inelastic supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inelastic supply</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Inelastic supply is when  a given change in price leads to a less than proportionate change in the amount supplied.</div>", "topic": "THEORY OF SUPPLY : ELASTICITY OF SUPPLY"}, {"id": "objective>Economics>2021 Model II>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The methods of measuring national income are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Expenditure, Output and income method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">GDP,NNP and GNP method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Percapita, value added and price index method</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Expenditure , Value added and per capita method</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The methods for measuring national income are : Expenditure, Income and output (value added) method.</div>", "topic": "NATIONAL INCOME : MEASUREMENT OF NATIONAL INCOME"}, {"id": "objective>Economics>2021 Model II>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Consumer price index is used to determine the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Standard of living</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Expectancy life</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cost of living</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Interest rate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The consumer price index measures relative changes in consumer prices over time. It is widely used to determine the cost of living. In addition, it is often used by economist and government officials to measure changes in the purchasing power of a given currency.</div>", "topic": "NATIONAL INCOME : DIFFERENCE BETWEEN STANDARD OF LIVING & COST OF LIVING"}, {"id": "objective>Economics>2021 Model II>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the median frrom the following set of score; 11, 15, 13, 18 and 7</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11</div>", "<div style=\"font-family:Cambria;font-size:17px;\">13</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The median is the middle number in a sorted, ascending or descending, list of numbers. To find the median, the numbers have to be listed in numerical order, so the list would be 7, 11, 13, 15, 18. The median is 13, which is the middle number.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF CENTRAL TENDENCY"}, {"id": "objective>Economics>2021 Model II>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Find the range of the distribution 19,  8, 16, 24, 40, 12, 10</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The range of a set of numbers is the difference between the largest and smallest values. In this case, the largest number is 40 and the smallest number is 8. So, the range is 40 - 8 = 32.</div>", "topic": "TOOLS FOR ECONOMIC ANALYSIS : MEASURE OF DISPERSION"}, {"id": "objective>Economics>2021 Model II>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The negative effect of inflation is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fall in standards of living</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increased employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtors gain</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduction in burden of debt</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The negative effects of inflation are: discourages savings, fall in standard of living, discourage investment, creditors lose etc</div>", "topic": "INFLATION & DEFLATION : EFFECT"}, {"id": "objective>Economics>2021 Model II>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A recessionary environment (economic slump) alongside inflation is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">stagflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost-push inflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">slumpflation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inflationary spiral</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Slumpflation emphasizes a recessionary environment (economic slump) alongside inflation — it's often considered more severe than stagflation.</div>", "topic": "INFLATION & DEFLATION : TYPES"}, {"id": "objective>Economics>2021 Model II>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Institutions established by member banks to settle cheques drawn on them is referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Clearing house</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Central Bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Commercial Bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Finance companies</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A clearing house is an institution formed by banks to facilitate the exchange of payments, securities, or derivatives transactions. The clearing house stands between two clearing firms (also known as member firms or clearing participants) and its purpose is to reduce the risk of one (or more) clearing firm failing to honor its trade settlement obligations. In this context, it is used to settle cheques drawn on the member banks.</div>", "topic": "FINANCIAL INSTITUTION : CHEQUES"}, {"id": "objective>Economics>2021 Model II>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Amount of assets that a bank is allowed to hold in liquid as a proportion of its total deposit is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">special deposit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquidity ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">special directive</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Liquidity ratio is also known as cash reserve, cash ratio. It is the amount of assets that a bank is allowed to hold in liquid form as a proportion of its total deposit.</div>", "topic": "FINANCIAL INSTITUTION : CENTRAL BANK"}, {"id": "objective>Economics>2021 Model II>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a firm produces less than the optimum output</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it is working its plant to full capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is not working its plant to full capacity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is overworking its plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is not working its plants</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A firm that produces less than the optimum output, it is working its plant to full capacity and if it produces beyond it is overworking its plants.</div>", "topic": "THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION"}, {"id": "objective>Economics>2021 Model II>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the LRAC is derived form a series of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">MC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SAC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AVC</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AR</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The LRAC(Long run average cost) is a flatter u-shape. The shape of the LRAC is derived from the SAC( Short run average cost)</div>", "topic": "THEORY OF PRODUCTION (2) : CONCEPTS OF PRODUCTION"}, {"id": "objective>Economics>2021 Model II>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a person consumes three apples, the marginal utility is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">first apple he consumes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">second apple he consumes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">third apple he consumes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">total utility</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Marginal utility is the satisfaction a consumer derived from the last units of consumption of an article. If a person consumes three units of an apple, the utility of the third apple is the marginal utility.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>2021 Model II>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The law of diminishing marginal utility is explain through the basis of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">law of supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">law of production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Law of demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">law of diminishing returns</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The law of diminishing marginal utility states that the amount of satisfaction an individual derives from additional units of a commodity decreases as his consumption of that commodity increases. The law is explain through the basis of law of demand which states that the higher the price, the lower the quantity demanded.</div>", "topic": "THEORY OF CONSUMER BEHAVIOUR : DIMINISHING MARGINAL UTILITY AND LAW OF DEMAND"}, {"id": "objective>Economics>2021 Model II>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Production possibility curve is explained through the concept of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">money cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">choice</div>", "<div style=\"font-family:Cambria;font-size:17px;\">opportunity cost</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scarcity</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Production Possibility Curve (PPC) is explained through the concept of 'opportunity cost'. The PPC is a graphical representation showing all possible combinations of two goods that can be produced with available resources and technology, at a given time. When we move from one point to another on the PPC, we give up some quantity of one good to gain more of the other good. The good that is given up is the opportunity cost of gaining the other good. Hence, the concept of opportunity cost is fundamental to the understanding of the PPC.</div>", "topic": "INTRODUCTION TO ECONOMICS : PRODUCTION POSSIBILITY CURVE"}, {"id": "objective>Economics>2021 Model II>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The demand curve for the MRP is downward sloping due to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Law of increasing returns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Law of returns to scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Law of variable proportion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">law of decreasing cost</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Law of variable proportion is also known as law of diminishing returns. The downward sloping of the Marginal Revenue product is due to law of diminishing returns i.e as more workers are hired, the MP of labour begins declining, causing the MRP of labour to fall as well.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2021 Model II>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A type of employment where people seems to be employed but are actually not is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Seasonal unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Residual unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Disguised unemployment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cyclical unemployment</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Disguised unemployment is also known as Hidden or concealed unemployment and it is a type of unemployment where some people seem to be employed but are actually not.</div>", "topic": "LABOUR MARKET AND UNEMPLOYMENT : THE CONCEPT OF UNEMPLOYMENT"}, {"id": "objective>Economics>2021 Model II>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to curb inflation, the government can</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase expenditure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase excess demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce production</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce expenditure</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In order to curb inflation by reducing excess demand, the government can reduce its expenditure and increase productivity.</div>", "topic": "INFLATION & DEFLATION : CAUSES & CONTROL"}, {"id": "objective>Economics>2021 Model II>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A policy used by the government to encourage production of commodities for export is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">small scale development strategy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large scale development strategy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">export promotion strategy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">import promotion strategy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Export promotion strategy is a deliberate strategy by the government aimed at encouraging the production of commodities for export.</div>", "topic": "ECONOMIC DEVELOPMENT : DEVELOPMENT PLANNING"}, {"id": "objective>Economics>2021 Model II>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The main canons of tax are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Simplicity, flexibility, elasticity and equity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equality, certainty, convenience and economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Productivity, neutrality, equality and certainty</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Equality, simplicity, equity and certainty</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The first set of principle of taxation was enunciated by Adam smith which he called canons of taxation in 1776. The canons of taxation are: Equality, certainty, convenience and economy.</div>", "topic": "PUBLIC FINANCE : PRINCIPLE OF TAXATION"}, {"id": "objective>Economics>2021 Model II>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Total population can be calculated as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Birth rate + Death rate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Pop density x land area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">No of females - No of males</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Death rate - Birth rate</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total population can be calculated as: <br/> - Tp= No of males + No of females <br/> - TP= Birth rate - Death rate <br/> - TP= Population density x land area</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2021 Model II>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The table belows shows the age distribution of people in a particular country <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Age  </td><td style=\"border:1px solid black;text-align:center;\"> population</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">0 - 17years</td><td style=\"border:1px solid black;text-align:center;\">     20</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">18- 60years</td><td style=\"border:1px solid black;text-align:center;\">    30</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">65years and above</td><td style=\"border:1px solid black;text-align:center;\">  40</td></tr></table></div> <br/> What is the dependency ratio?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3:2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2:1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1:2</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">Dependency</td><td style=\"text-align:center;\">ratio</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Dependent population<hr size=\"1\" />Independent population</td><td style=\"text-align:center;\"></td></tr></table></div>                               <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=20+40<hr size=\"1\" />30</td><td style=\"text-align:center;\"></td></tr></table></div> <br/>  <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">2<hr size=\"1\" />1</td><td style=\"text-align:center;\">= 2:1</td><td style=\"text-align:center;\"></td></tr></table></div></div>", "topic": "POPULATION : POPULATION STRUCTURE/ DISTRIBUTION"}, {"id": "objective>Economics>2021 Model II>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of Absolute Cost Advantage was propounded by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Adam Smith</div>", "<div style=\"font-family:Cambria;font-size:17px;\">David Ricardo</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AC Pigou</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Alfred Marshal</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The principle of Absolute cost advantage was propounded by Adam Smith. Adam Smith propounded the theory of absolute cost advantage as the basis of foreign trade; under such circumstances an exchange of goods will take place only if each of the two countries can produce one commodity at an absolute lower production cost than the other country.  <br/>  <br/> </div>", "topic": "INTERNATIONAL TRADE : PRINCIPLES OF INTERNATIONAL TRADE"}, {"id": "objective>Economics>2021 Model II>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The causes of farmer's unstable income include all except</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The vagaries of the weather</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The effect of diseases and pest</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The formation of famer's co-operatives</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Monocropping</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The instability in agricultural incomes are weather, diseases and pest, poor storage facilities, changes in demand for agricultural exports and monocropping or reliance on single crops.</div>", "topic": "AGRICULTURE IN WEST AFRICA : FEATURES"}, {"id": "objective>Economics>2021 Model II>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Economic development embraces both</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Growth plus changes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Growth plus indicators</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in output</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Changes in size and output</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Economic development is the process whereby the level of national production or per capita income increases over a period of time. It is taken to mean growth plus change.Infact it embraces both growth and decline.</div>", "topic": "ECONOMIC DEVELOPMENT : INTRODUCTION"}, {"id": "objective>Economics>2021 Model II>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the negative effect of petroleum on the Nigeria economy is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">source of government revenue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over- reliance on oil</div>", "<div style=\"font-family:Cambria;font-size:17px;\">source of employment</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provision of raw materials</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The negative effects of petroleum on the Nigeria economy are: <br/> - Over- reliance( dependence) on oil and neglect of the agriculture sector <br/> - Urban congestion <br/> - High rate of inflation <br/> - Oil spillage <br/> - political and social unrest in oil producing areas</div>", "topic": "PETROLEUM AND THE NIGERIA ECONOMY : INTRODUCTION"}, {"id": "objective>Economics>2021 Model II>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below  to answer the question that follows: <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/>  <br/> From the diagram above, the point \"X\" illustrates </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">equilibrium point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess demand</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess supply</div>", "<div style=\"font-family:Cambria;font-size:17px;\">price determination point</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the diagram above, \"x\" is above the equilibrium price. Price above the equilibrium price indicates supply is greater than demand which will lead to surplus or  excess supply.</div>", "topic": "THE THEORY OF PRICE DETERMINATION : CONCEPT OF MARKET AND PRICE"}, {"id": "objective>Economics>2021 Model II>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Nigeria economy is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Capitalist economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Socialist economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Command economy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Mixed economy</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Nigeria economy is a mixed economy in which the means of production is controlled by an individual and the states (government).</div>", "topic": "ECONOMIC SYSTEM : TYPES AND FEATURES OF ECONOMIC SYSTEM"}, {"id": "objective>Economics>2021 Model II>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The amount of money income received by workers for their services in production is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Real wages</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Quasi- Rent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Surplus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nominal wages</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nominal wages is also known as Money wages. It is the wages related to the amount of money income received by workers for their services in production. </div>", "topic": "FACTORS OF PRODUCTION & THEIR THEORIES : WAGES"}, {"id": "objective>Economics>2021 Model II>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Wholesaler are considered a bulk breaker because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">provide loan to the producers</div>", "<div style=\"font-family:Cambria;font-size:17px;\">provide warehousing facilities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sell in smaller quantity to the retailer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sell in smaller quantities to the consumer</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The wholesaler purchases goods in bulk or large quantity from the manufacturer and sells in small quantities to the retailers.</div>", "topic": "DISTRIBUTIVE TRADE : THE WHOLESALER"}, {"id": "objective>Economics>2021 Model II>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A shareholder partakes in the profit of a limited liability company by receiving</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dividends</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gifts</div>", "<div style=\"font-family:Cambria;font-size:17px;\">profit</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shares</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Shareholders partake in the profits of a limited liability company by receiving dividends. Dividends are a portion of a company's earnings that are paid out to shareholders. They do not receive profits directly (which eliminates option 3), and while they may receive gifts or additional shares, these are not the primary ways they partake in the company's profits.</div>", "topic": "BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES"}, {"id": "objective>Economics>2021 Model II>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The capital needed for day to day running of a business is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">issued capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">working capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed capital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">social capital</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Working capital refers to the funds required to cover a company's short-term operational expenses and support its ongoing business activities. It represents the difference between current assets (such as cash, accounts receivable, and inventory) and current liabilities (such as accounts payable and short-term debts).</div>", "topic": "BUSINESS ORGANISATION : INTRODUCTION"}, {"id": "objective>Economics>2021 Model II>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If the population of a city increased from 15,000,000 to 18,000,000 between 2016 to 2017, calculate the growth rate</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16.67%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20.73%</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20%</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Growth rate = 18,000,000 - 15,000,000/ 15,000,000   x  100 <br/>                             = 3,000,000/ 15,000,000  x 100 <br/>                                          =  20%</div>", "topic": "POPULATION : DETERMINANTS OF POPULATION SIZE"}, {"id": "objective>Economics>2021 Model II>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is not a basic economic problem of the society?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Efficient use of resources</div>", "<div style=\"font-family:Cambria;font-size:17px;\">For whom to produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">How to produce</div>", "<div style=\"font-family:Cambria;font-size:17px;\">what to produce</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The efficient use of resources is not a basic economic problem but rather a solution to the economic problem. The basic economic problems of society are what to produce, how to produce, and for whom to produce. These problems arise due to the scarcity of resources. The efficient use of resources is a method to solve these problems by maximizing the output from the available resources.</div>", "topic": "ECONOMIC SYSTEM : ECONOMIC PROBLEMS OF THE SOCIETY"}];
